effect.shader:
vec3 rotUV( vec3 yuv, float degrees ) {
    float rad = degrees * 0.0174533;
    highp mat3 rmat = mat3(
        1.0,  0.0,       0.0,
        0.0,  cos(rad),  sin(rad),
        0.0,  -sin(rad), cos(rad)
    );
    return yuv * rmat;
}

vec3 hsv2rgb(vec3 c)
{
    vec4 K = vec4(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);
    vec3 p = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);
    return c.z * mix(K.xxx, clamp(p - K.xxx, 0.0, 1.0), c.y);
}

void main() {
    //float hue = lift.x;
    //float strength = lift.y;
    highp mat3 rgb2yuv = mat3(
         0.299,     0.587,    0.114,
        -0.14713,  -0.28886,  0.436,
         0.615,    -0.51499, -0.10001
    );
    highp mat3 yuv2rgb = mat3(
        1.0,  0.0,      1.13983,
        1.0, -0.39465, -0.58060,
        1.0,  2.03211,  0.0
    );

    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    highp vec3 rgb = texColor.rgb;
    lowp float a = texColor.a;
    highp vec3 yuv = rgb * rgb2yuv;

    //highp vec3 liftYUV = rotUV(vec3(0.5,-0.5,0.5),-lift.x) * lift.y / 2.;
    //highp vec3 gammaYUV = rotUV(vec3(0.5,-0.5,0.5),-gamma.x) * gamma.y / 2.;
    //highp vec3 gainYUV = rotUV(vec3(0.5,-0.5,0.5),-gain.x) * gain.y / 2.;

    highp vec3 liftYUV = (hsv2rgb(vec3(lift.x/360.,1.,0.5)) * rgb2yuv) * lift.y;
    highp vec3 gammaYUV = (hsv2rgb(vec3(gamma.x/360.,1.,0.5)) * rgb2yuv) * gamma.y;
    highp vec3 gainYUV = (hsv2rgb(vec3(gain.x/360.,1.,0.5)) * rgb2yuv) * gain.y;
    highp vec3 offsetYUV = (hsv2rgb(vec3(offset.x/360.,1.,0.5)) * rgb2yuv) * offset.y;


    // -- Do work here in YUV space ----

    //yuv = yuv * huemat;
    float y = yuv.x;

    float ygamma = pow(abs((y-0.5)*2.),2.);

    yuv.yz += liftYUV.yz * ((1.-y)*(1.-y)) * a;
    yuv.x += ((1.-y)*(1.-y))*lift.z * a;
    yuv.yz += gammaYUV.yz * ygamma * a;
    yuv.x += gamma.z * ygamma * a;
    yuv.yz += gainYUV.yz * (y*y) * a;
    yuv.x += gain.z * (y*y) * a;
    yuv.yz += offsetYUV.yz * a;
    yuv.x += offset.z * a;

    // -- Back to RGB and return result ---
    rgb = yuv * yuv2rgb;
    gl_FragColor = vec4(rgb,a);
}
